"use strict";(globalThis.webpackChunkdocs=globalThis.webpackChunkdocs||[]).push([[16844],{10544(e,t,i){i.r(t),i.d(t,{assets:()=>l,contentTitle:()=>a,default:()=>h,frontMatter:()=>r,metadata:()=>n,toc:()=>c});const n=JSON.parse('{"id":"scs-0129-v1-time-sync-decisions","title":"Decision on Standardized Time Synchronization","description":"Abstract","source":"@site/standards/scs-0129-v1-time-sync-decisions.md","sourceDirName":".","slug":"/scs-0129-v1-time-sync-decisions","permalink":"/standards/scs-0129-v1-time-sync-decisions","draft":false,"unlisted":false,"tags":[],"version":"current","frontMatter":{"title":"Decision on Standardized Time Synchronization","type":"Decision Record","status":"Draft","track":"IaaS"},"sidebar":"standards","previous":{"title":"scs-0129: Decision on Standardized Time Synchronization","permalink":"/standards/iaas/scs-0129"},"next":{"title":"KaaS Standards","permalink":"/standards/kaas/"}}');var s=i(74848),o=i(28453);const r={title:"Decision on Standardized Time Synchronization",type:"Decision Record",status:"Draft",track:"IaaS"},a=void 0,l={},c=[{value:"Abstract",id:"abstract",level:2},{value:"Terminology",id:"terminology",level:2},{value:"Context",id:"context",level:2},{value:"RTC emulation",id:"rtc-emulation",level:3},{value:"NTP/SNTP",id:"ntpsntp",level:3},{value:"PTP",id:"ptp",level:3},{value:"Paravirtualization",id:"paravirtualization",level:3},{value:"Decision",id:"decision",level:2},{value:"Consequences",id:"consequences",level:2}];function d(e){const t={code:"code",em:"em",h2:"h2",h3:"h3",li:"li",ol:"ol",p:"p",ul:"ul",...(0,o.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(t.h2,{id:"abstract",children:"Abstract"}),"\n",(0,s.jsx)(t.p,{children:"System clocks of virtual machines may drift over time, and will also be affected by pausing or migrating the VM.\nEnsuring a correct system time usually requires synchronization with an external time source.\nThere are multiple options for VM clock synchronization which this document will explore and evaluate for standardization in SCS."}),"\n",(0,s.jsx)(t.h2,{id:"terminology",children:"Terminology"}),"\n",(0,s.jsx)(t.p,{children:"(TBD)"}),"\n",(0,s.jsx)(t.h2,{id:"context",children:"Context"}),"\n",(0,s.jsx)(t.p,{children:"Correct system time is important for the validation of TLS certificates and correlation of log entries across multiple systems.\nTo counteract drifting of the system time, it is common practice to syncronize servers to a public time server via the NTP protocol.\nThis requires access to the internet, however, and the network latency encountered when connecting to a public NTP server may reduce the clock precision.\nCommunicating with an external NTP server will also expose small bits of information (mainly the existence of the system) to the operator of the time server."}),"\n",(0,s.jsx)(t.p,{children:"Ideally, the CSP would provide a means of time synchronization to servers, so that no outward NTP traffic is necessary.\nDoing so comes with two challenges:"}),"\n",(0,s.jsxs)(t.ol,{children:["\n",(0,s.jsx)(t.li,{children:"Providing an apropriate method of time synchronization. This could be NTP, PTP, hardware clock emulation or para-virtualization."}),"\n",(0,s.jsx)(t.li,{children:"Getting guest servers to actually use the provided time synchronization method. This may involve preconfigured images, DHCP, cloud metadata, or user interaction."}),"\n"]}),"\n",(0,s.jsx)(t.p,{children:"The options for configuring time synchronisation in guests are often dependant on the method of synchronisation, so it makes most sense to discuss them in that context."}),"\n",(0,s.jsx)(t.h3,{id:"rtc-emulation",children:"RTC emulation"}),"\n",(0,s.jsx)(t.p,{children:"Since their early days, IBM-compatible PCs have included a battery-backed real-time clock (RTC).\nOriginally this was the MC146818 CMOS clock, which was able keeps track of seconds, minutes, hours, days, months, and years.\nAs other manufacturers replicated the interface of the chip, it became a defacto standard and is supported by practically all operating systems designed to run on a PC platform."}),"\n",(0,s.jsx)(t.p,{children:"Qemu supports emulation of a MC146818-compatible clock that will by default replicate the host's system time, but can also set to run independently (which will also keep the time from moving on for suspended guests).\nIf the host itself is synchronized to an acurate time source, then the emulated RTC of the guest will be equally accurate."}),"\n",(0,s.jsx)(t.p,{children:"The benefits of an emulated RTC are its wide support among guest operating systems and it's independence from network connectivity."}),"\n",(0,s.jsx)(t.p,{children:"The main disadavantage is it's low resolution of only one second.\nLinux will typically initialize the system time on boot using the RTC and then use a higher resolution clock source (like the CPU's timestamp counter) to advance the system time without resyncing with the RTC.\nIt is possible to resync the system time to the RTC, but that appears not to be default behavior, so any outside time corrections would typically be lost on a running system."}),"\n",(0,s.jsx)(t.p,{children:"Another drawback of RTC emulation is it's reliance on the hypervisor, though it seems likely that other hypervisors besides KVM/Qemu would have similar features."}),"\n",(0,s.jsx)(t.h3,{id:"ntpsntp",children:"NTP/SNTP"}),"\n",(0,s.jsx)(t.p,{children:"The Network Time Protocol (NTP) is a UDP-based protocol used to synchronize time between a client and one or multiple servers.\nNTP will transmit the current time of the server, but also try to determine and correct for the transmission delay.\nOut of multiple time servers, it will try to select the most accurate one.\nDepending on the network distance of the time server and factors such as network congestion, NTP can achive acuracy from 100ms down to less then 1ms."}),"\n",(0,s.jsx)(t.p,{children:"The Simple Network Time Protocol (SNTP) is a simplified (but compatible) subset of NTP that only allows synchronization to a single server and is generally less acurate."}),"\n",(0,s.jsxs)(t.p,{children:["Most ready-made cloud images will include an NTP client (typically ",(0,s.jsx)(t.em,{children:"chrony"}),"), or at least an SNTP client (typically ",(0,s.jsx)(t.em,{children:"systemd-timesyncd"}),"), with a preconfigured public NTP server or server pool.\nThey will mostly also accept NTP servers supplied via DHCP, which allows CSPs to automatically provide their own local NTP servers for improved accuracy.\nThis will not work in all cases though, because Openstack supports the configuration of servers without DHCP, and also because the OVN implementation of DHCPv6 is still missing support for providing NTP servers."]}),"\n",(0,s.jsx)(t.p,{children:"If servers are configured without DHCP, they must get their network configuration from the metadata provided via config drive.\nThere is currently no standardized field to supply NTP servers in either Openstacks own metadata format, or the EC2 Format which Openstack also supports."}),"\n",(0,s.jsx)(t.p,{children:"Openstacks own metadata format also supports vendor data, which is an unstructured JSON document that can be used to pass CSP-specific information to servers.\nThis document could be used to communicate local NTP servers, though there is currently no established format for this."}),"\n",(0,s.jsxs)(t.p,{children:["Cloud-init does support embedding its own ",(0,s.jsx)(t.em,{children:"cloud-config"})," format into openstack vendor data, which does have support for configuring NTP.\nThis feature is rather intrusive, however, as cloud-init will attempt to install NTP client packages if it finds that none are present in the system."]}),"\n",(0,s.jsx)(t.p,{children:"Some IaaS providers, such as AWS and GCP, will provide their own NTP servers to VMs under a fixed link-local IP address, which are often preconfigured in images targeting those platforms."}),"\n",(0,s.jsx)(t.h3,{id:"ptp",children:"PTP"}),"\n",(0,s.jsx)(t.p,{children:"The Precision Time Protocol (PTP) is, like NTP, a network-based time synchronization protocol, that supports both UDP and ethernet transports.\nPTP is designed to offer higher precision than NTP, particularly in local area networks, e.g. by measuring the timing of synchronization messages directly at the network interface, if supported.\nMaster clocks will also continually broadcast synchronization messages to their network, making them discoverable for clients, but also generating more traffic than NTP."}),"\n",(0,s.jsxs)(t.p,{children:["Linux has a kernel-based driver for PTP, which will provide the synchronized time through a device file, which can then be used by services such as ",(0,s.jsx)(t.em,{children:"phc2sys"})," or ",(0,s.jsx)(t.em,{children:"chrony"})," to update the system time."]}),"\n",(0,s.jsx)(t.p,{children:"It is unclear if PTP would offer any better precision than NTP in tunneled networks with virtual interfaces, and it does not seem to get any use in IaaS at all."}),"\n",(0,s.jsx)(t.h3,{id:"paravirtualization",children:"Paravirtualization"}),"\n",(0,s.jsxs)(t.p,{children:["Unlike PTP as a protocol, it's driver interface in Linux seems to be a popular choice for time synchronization in the form of paravirtualization.\nThe ",(0,s.jsx)(t.em,{children:"ptp_kvm"})," kernel module will communicate directly with the KVM hypervisor to provide a PTP device file that follows the system time of the host.\nHyper-V also offers time synchronization through a PTP device file, managed by its ",(0,s.jsx)(t.em,{children:"Linux Integration Services"}),"."]}),"\n",(0,s.jsx)(t.p,{children:"Paravirtualized time synchronization has the benefit of generally offering the highest precision.\nLike RTC clock emulation, it also works independently of the guest system's network connectivity.\nThe main drawback is the dependency on a specific combination of hypervisor and guest operating system, because it requires hypervisor-specific drivers to run in the guest."}),"\n",(0,s.jsx)(t.h2,{id:"decision",children:"Decision"}),"\n",(0,s.jsx)(t.p,{children:"From looking at the available options, it becomes apparent that there is no single optimal solution for time synchronization.\nThe most precise option is the least portable, but the most widely supported option also requires the most provider-specific configuration."}),"\n",(0,s.jsx)(t.p,{children:"The aim of SCS is to improve interoperability between Openstack clouds, so the preferable standard solution is one that works across a wide range of setups.\nThis perspective clearly favours NTP as a standardized method of time synchronization, because of it's wide support in cloud images and it's independence from other components, such as the hypervisor."}),"\n",(0,s.jsx)(t.p,{children:"However it is still useful for a CSP to offer less portable, but more precise methods of time synchronization, especially if they are integrated into the default cloud images offered by the CSP."}),"\n",(0,s.jsx)(t.p,{children:"So, we should standardize a portable NTP setup that users can assume when developing images to work well in any SCS cloud.\nWe should not try to prevent CSPs from also supporting paravirtualized or other methods of time synchronization that may offer significant benefits over NTP."}),"\n",(0,s.jsx)(t.p,{children:"We should consider setting quality requirements, for example limiting the acceptable offset and jitter of the synchronized time.\nThe specific limits should be informed by research into the requirements of popular quorum-based distributed services, such as RabbitMQ, Zookeeper, and Ceph, which tend to be sensitive to relative time drift."}),"\n",(0,s.jsx)(t.p,{children:"We should also work towards upstream OpenStack support for injecting locally synced NTP servers into subnets, comparable to Neutron's support for injecting DHCP servers and providing local DNS resolution.\nThis would be an optimal target for standardization, because it would allow time synchronization in isolated networks, and, depending on the implementation, may also help to improve precision and scalability."}),"\n",(0,s.jsx)(t.p,{children:"Lastly, we should consider giving requirements, or at least guidelines, to CSPs regarding time synchronization in their internal infrastructure, especially if this forms the basis for the synchronisation of guests."}),"\n",(0,s.jsx)(t.h2,{id:"consequences",children:"Consequences"}),"\n",(0,s.jsx)(t.p,{children:"A standardized NTP setup will allow SCS users and third party image providers to develop images that support local time synchronization across SCS clouds."}),"\n",(0,s.jsx)(t.p,{children:"As discussed in the NTP section above, there are a number of limitations in OpenStack and related projects that a standardized NTP setup has to work with:"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsxs)(t.li,{children:["OpenStack currently has no support for providing NTP servers to VMs under a fixed link-local address, like AWS and GCP are doing.\nSuch a feature could probably be implemented by re-using the metadata service IP (",(0,s.jsx)(t.code,{children:"169.254.169.254"}),") and the mechanisms to inject it into subnets.\nWhile this would be a great target for standardization, we will first need to get it accepted by the upstream OpenStack community."]}),"\n",(0,s.jsx)(t.li,{children:"Alternatively, making NTP servers accessible via provider networks will limit availability to those VMs that are connected to the provider network, either directly or via a virtual router"}),"\n",(0,s.jsx)(t.li,{children:"CSPs will need a method of informing VMs of available NTP servers.\nDHCP is the currently best supported mechanism for this, but is not guaranteed to be available to VMs, as users may disable it for their subnets.\nAlso, OVN's DHCPv6 implementation currently does not support the required option, but that seems to be a relatively straightforward feature to add."}),"\n",(0,s.jsx)(t.li,{children:"The alternative to DHCP is of course the metadata service, though there is currently no standard field for providing NTP servers.\nCloud-init's proprietary format may not be good option because of the automatic package installation in guests, but any other option will require support to be added to whatever init tool is used.\nA new NTP server key in OpenStack's standard metadata will require upstream changes, but is more likely to get supported by cloud-init or other init tools (though most seem to focus exclusively on the EC2 format).\nA custom key in the vendor data could just be defined in the standard, but would be less likely to get support by any third party tools, and thus only be useful with custom scripts or init-tool plugins."}),"\n"]})]})}function h(e={}){const{wrapper:t}={...(0,o.R)(),...e.components};return t?(0,s.jsx)(t,{...e,children:(0,s.jsx)(d,{...e})}):d(e)}},28453(e,t,i){i.d(t,{R:()=>r,x:()=>a});var n=i(96540);const s={},o=n.createContext(s);function r(e){const t=n.useContext(o);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function a(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:r(e.components),n.createElement(o.Provider,{value:t},e.children)}}}]);